    uint16_t header;
    std::string data;
    uint32_t footer;
};

std::vector<uint8_t> serialize_with_padding(const PaddedData& packet) {
    // Create a vector to hold the serialized data
    std::vector<uint8_t> buffer;

    // Create a buffer_adaptor for the vector
    hexi::buffer_adaptor<std::vector<uint8_t>> adaptor(buffer);

    // Create a binary_stream using the buffer_adaptor
    hexi::binary_stream<decltype(adaptor)> stream(adaptor);

    // Write header using operator<<
    stream << packet.header;

    // Write data string with prefix using operator<< (automatically adds prefix)
    stream << packet.data;

    // Write 16 bytes of padding using fill<16>(0x00)
    stream.fill<16>(0x00);

    // Write footer using operator<<
    stream << packet.footer;

    return buffer;
}

