    }
    stream.write_container(converted_data);

    // Convert checksum to big-endian and write
    auto converted_checksum = hexi::endian::native_to_big(packet.checksum);
    stream.write(&converted_checksum, 1);

    return buffer;
}

ProtocolPacket deserialize_protocol_packet(const std::span<const uint8_t> buffer) {
    ProtocolPacket packet;

    // Create binary_stream for reading from the buffer
    std::vector<uint8_t> buffer_copy(buffer.begin(), buffer.end());
    hexi::binary_stream<std::vector<uint8_t>> stream(buffer_copy);

    // Read and convert message_id
    uint32_t msg_id;
    stream.read(&msg_id, 1);
    packet.message_id = hexi::endian::big_to_native(msg_id);

    // Read and convert data_values count
    uint32_t count;
    stream.read(&count, 1);
    packet.data_values.resize(count);

    // Read and convert data_values vector
    stream.read_container(packet.data_values, [&](uint16_t& value, hexi::binary_stream<std::vector<uint8_t>>& stream, size_t index) {
        stream.read(&value, 1);
        packet.data_values[index] = hexi::endian::big_to_native(value);
